import os

def generate_key():
    return Fernet.generate_key()

def encrypt_credit_card(card_number, key):
    cipher_suite = Fernet(key)
    encrypted_card_number = cipher_suite.encrypt(card_number.encode())
    return encrypted_card_number.decode()

def decrypt_credit_card(encrypted_card_number, key):
    cipher_suite = Fernet(key)
    decrypted_card_number = cipher_suite.decrypt(encrypted_card_number.encode()).decode()
    return decrypted_card_number

